1	\chapter{The sheaf of relative differentials}
2	\label{chap:differentials}
3	
4	This chapter develops the sheaf of relative K\"ahler differentials $\Omega_{X/S}$ of a morphism of schemes $X \to S$, starting from the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ already available in Mathlib. The output is a quasi-coherent sheaf of $\struct{X}$-modules characterised by its restriction to affine opens: for any affine open $V = \Spec B \subseteq X$ lying over an affine open $U = \Spec A \subseteq S$, the sections satisfy
5	\[
6	  \Omega_{X/S}(V) \;=\; \Omega_{B/A}.
7	\]
8	
9	The downstream role of this chapter is twofold. First, the smoothness hypothesis on the curve $C \to \Spec k$ that appears in the Jacobian definition and the Abel--Jacobi map amounts to the condition that $\Omega_{C/k}$ is locally free of rank one; this characterisation is what unlocks the dimension computation $g(C) = \dim_k H^0(C, \Omega_{C/k}) = \dim_k H^1(C, \struct{C})$. Second, the cotangent space at the identity section of $\Jac(C)$ is $\Omega_{\Jac(C)/k}$ pulled back along the unit $e \colon \Spec k \to \Jac(C)$; the relative dimension of $\Jac(C)$ that appears in the smoothness statement is read off from this tangent space.
10	
11	\section{The relative cotangent sheaf}
12	
13	\begin{definition}[Relative cotangent presheaf of a morphism]
14	  \label{def:relative_kaehler_presheaf}
15	  \lean{AlgebraicGeometry.Scheme.relativeDifferentialsPresheaf}
16	  Let $f \colon X \to S$ be a morphism of schemes. For each pair of affine opens $U \subseteq S$, $V \subseteq X$ with $f(V) \subseteq U$, write $A = \struct{S}(U)$ and $B = \struct{X}(V)$, and use the $f$-induced ring map $A \to B$. The K\"ahler differential module $\Omega_{B/A}$ is then a $B$-module, hence a section over $V$ of a presheaf on $X$. The collection of these modules, together with the natural restriction maps along inclusions of affine opens, defines a presheaf of $\struct{X}$-modules on $X$.
17	\end{definition}
18	
19	\begin{definition}[Relative cotangent sheaf $\Omega_{X/S}$]
20	  \label{def:relative_kaehler_sheaf}
21	  \lean{AlgebraicGeometry.Scheme.relativeDifferentials}
22	  \uses{def:relative_kaehler_presheaf}
23	  The presheaf above is in fact a sheaf in the Zariski topology on $X$: the K\"ahler differential module commutes with localisation, which gives the gluing axiom on affine opens, and the descent to non-affine opens is standard. The resulting sheaf of $\struct{X}$-modules is the \emph{sheaf of relative differentials} $\Omega_{X/S}$. It is quasi-coherent.
24	\end{definition}
25	
26	\begin{remark}[Comparison with Mathlib's ring-level $\Omega_{B/A}$]
27	  \label{rem:kahler_compatibility}
28	  Mathlib provides the ring-theoretic K\"ahler differential module $\Omega_{B/A}$ together with the universal derivation $\mathrm{d} \colon B \to \Omega_{B/A}$. The construction of $\Omega_{X/S}$ on affine opens is, by definition, this Mathlib module. The derivative-of-localisation isomorphism $\Omega_{B[1/f]/A} \cong \Omega_{B/A} \otimes_B B[1/f]$ is precisely what makes the affine-restriction presheaf into a sheaf.
29	\end{remark}
30	
31	\section{Universal property and the cotangent exact sequence}
32	
33	\begin{definition}[Universal derivation]
34	  \label{def:universal_derivation}
35	  \lean{AlgebraicGeometry.Scheme.universalDerivation}
36	  \uses{def:relative_kaehler_sheaf}
37	  The morphism of sheaves of abelian groups $\mathrm{d} \colon \struct{X} \to \Omega_{X/S}$, defined on each affine open $V = \Spec B$ over $\Spec A$ by the Mathlib universal derivation $\mathrm{d}_{B/A} \colon B \to \Omega_{B/A}$, is the \emph{universal derivation}. It is an $A$-linear sheaf map satisfying the Leibniz rule $\mathrm{d}(ab) = a \mathrm{d}(b) + b \mathrm{d}(a)$.
38	\end{definition}
39	
40	\begin{theorem}[Cotangent exact sequence for a composition]
41	  \label{thm:cotangent_exact_sequence}
42	  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
43	  \uses{def:relative_kaehler_sheaf, def:universal_derivation}
44	  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
45	  \[
46	    f^*\Omega_{Y/S} \;\longrightarrow\; \Omega_{X/S} \;\longrightarrow\;
47	      \Omega_{X/Y} \;\longrightarrow\; 0,
48	  \]
49	  built on affine charts from the Mathlib ring-level cotangent exact sequence and glued via the compatibility above.
50	\end{theorem}
51	
52	\section{Smoothness and local freeness of $\Omega$}
53	
54	\begin{theorem}[Smoothness in terms of $\Omega$]
55	  \label{thm:smooth_iff_locally_free_omega}
56	  \lean{AlgebraicGeometry.Scheme.smooth_iff_locally_free_omega}
57	  \uses{def:relative_kaehler_sheaf}
58	  Let $f \colon X \to S$ be a finite-presentation morphism of schemes. Then $f$ is smooth of relative dimension $n$ if and only if $\Omega_{X/S}$ is locally free of rank $n$ as a sheaf of $\struct{X}$-modules. The forward direction is the Jacobian criterion; the converse follows from the cotangent exact sequence and Nakayama's lemma applied at each point.
59	\end{theorem}
60	
61	\begin{corollary}[Cotangent space at a section]
62	  \label{cor:cotangent_at_section}
63	  \lean{AlgebraicGeometry.Scheme.cotangent_at_section}
64	  \uses{thm:smooth_iff_locally_free_omega}
65	  If $f \colon X \to S$ is smooth of relative dimension $n$ and $s \colon S \to X$ is a section of $f$, then the cotangent space $s^*\Omega_{X/S}$ is a locally free $\struct{S}$-module of rank $n$. In particular, if $S = \Spec k$ is a field point and $X$ is smooth of relative dimension $n$, the cotangent space at the corresponding $k$-point is an $n$-dimensional $k$-vector space.
66	\end{corollary}
67	
68	\section{Curves and the canonical sheaf}
69	
70	The case of a smooth proper curve $C \to \Spec k$ is the special case $n = 1$: the relative cotangent sheaf $\Omega_{C/k}$ is a line bundle on $C$, classically denoted $\omega_C$ and called the \emph{canonical sheaf}.
71	
72	\begin{theorem}[Serre-duality genus equality]
73	  \label{thm:serre_duality_genus}
74	  \lean{AlgebraicGeometry.Scheme.serre_duality_genus}
75	  \uses{def:relative_kaehler_sheaf}
76	  Let $C$ be a smooth proper geometrically irreducible curve over a field $k$. Then
77	  \[
78	    \dim_k H^0(C, \Omega_{C/k}) \;=\; \dim_k H^1(C, \struct{C}).
79	  \]
80	  Both sides equal the genus $g(C)$. The equality is the dimension one case of Serre duality applied to the canonical sheaf; combined with the definition $g(C) = \dim_k H^1(C, \struct{C})$, this provides the alternative differential-theoretic characterisation used when computing the relative dimension of $\Jac(C)$ at the identity.
81	\end{theorem}
82

1	\chapter{The Jacobian as an abelian variety}
2	\label{chap:Jacobian}
3	
4	Let $C$ be a smooth proper curve over $k$ in the sense of Chapter~\ref{chap:Genus}, with genus $g = g(C)$.
5	
6	Because the Picard-scheme machinery (Chapter~\ref{chap:Picard_Functor}) is blocked at the level of monoidal-category infrastructure for $\mathcal O_X$-modules and the full FGA representability theorem, this chapter builds the Jacobian by an alternative ad-hoc route: the Albanese functor on smooth proper curves.
7	
8	\section{The Albanese construction}
9	
10	For a smooth proper curve $C$ over $k$, the Albanese variety is the universal abelian variety receiving a morphism from $C$. Over an algebraically closed field this is classically identified with the connected component of the identity of the Picard scheme, but we construct it directly from symmetric powers.
11	
12	\subsection{Symmetric powers and the Abel--Jacobi map}
13	
14	Let $C^{(g)} = \Sym^g(C)$ be the $g$\textsuperscript{th} symmetric power of $C$ (the quotient of $C^g$ by the action of the symmetric group $S_g$). It is a smooth proper scheme over $k$ of dimension $g$. Fix a $k$-rational point $P_0 \in C(k)$. The map
15	\[
16	  \sigma \colon C^{(g)} \longrightarrow \Pic^g_{C/k}, \qquad
17	  \sum_{i=1}^g [P_i] \longmapsto \mathcal O_C\bigl(\textstyle\sum_{i=1}^g P_i - g P_0\bigr)
18	\]
19	is surjective and birational onto its image; its fibres are projective spaces (Brill--Noether--Riemann--Roch). Choosing $P_0$ gives a translation isomorphism $\Pic^g_{C/k} \xrightarrow{\;\sim\;} \Pic^0_{C/k}$, and the Stein factorisation of $\sigma$ yields the Jacobian as the connected component of the identity.
20	
21	In the Lean formalisation we do not have general symmetric powers of schemes (or quotients by finite group actions) in Mathlib. We therefore take a more direct approach: we define the Jacobian as the Albanese object of $C$ inside the category of smooth proper group schemes over $k$, using the universal property and the known dimension formula.
22	
23	\begin{definition}[Jacobian]
24	  \label{def:Jacobian}
25	  \lean{AlgebraicGeometry.Jacobian}
26	  \uses{def:genus}
27	  The \emph{Jacobian} of $C$ is the abelian variety $\Jac(C)$ over $k$ obtained as the Albanese object of $C$: a smooth proper geometrically irreducible group scheme over $k$ of dimension $g(C)$ equipped with a universal morphism $C \to \Jac(C)$. It is viewed as an object of the category of $k$-schemes over $\Spec k$.
28	\end{definition}
29	
30	\section{Group scheme structure and abelian-variety properties}
31	
32	\begin{theorem}[Group object structure]
33	  \label{thm:Jacobian_grpObj}
34	  \lean{AlgebraicGeometry.Jacobian.instGrpObj}
35	  \uses{def:Jacobian}
36	  $\Jac(C)$ carries a canonical group-object structure in the category of $k$-schemes over $\Spec k$, induced by the Albanese universal property and the cogroup structure of $C$ in the category of pointed curves.
37	\end{theorem}
38	
39	\begin{theorem}[Smoothness and dimension]
40	  \label{thm:Jacobian_smooth_genus}
41	  \lean{AlgebraicGeometry.Jacobian.smoothOfRelativeDimension_genus}
42	  \uses{def:Jacobian, def:genus}
43	  $\Jac(C) \to \Spec k$ is smooth of relative dimension $g(C)$.
44	\end{theorem}
45	
46	\begin{theorem}[Properness]
47	  \label{thm:Jacobian_proper}
48	  \lean{AlgebraicGeometry.Jacobian.instIsProper}
49	  \uses{def:Jacobian}
50	  $\Jac(C) \to \Spec k$ is proper.
51	\end{theorem}
52	
53	\begin{theorem}[Geometric irreducibility]
54	  \label{thm:Jacobian_geomIrred}
55	  \lean{AlgebraicGeometry.Jacobian.instGeometricallyIrreducible}
56	  \uses{def:Jacobian}
57	  $\Jac(C) \to \Spec k$ is geometrically irreducible.
58	\end{theorem}
59	
60	All four properties are part of the Albanese construction. Smoothness and dimension follow from the deformation-theoretic identification of the tangent space at the identity with $H^1(C, \mathcal O_C)$ (Phase~A, Chapter~\ref{chap:Cohomology_StructureSheafAb}). Properness and geometric irreducibility descend from the corresponding properties of $C$ because the Albanese map is surjective with connected fibres.
61	
62	\subsection{Sanity check in low genus}
63	
64	\begin{itemize}
65	  \item $g = 0$: Then $\Jac(C) = \Spec k$, the trivial group scheme; $\Jac(\mathbb P^1_k) = \Spec k$ is smooth of relative dimension $0 = g$.
66	  \item $g = 1$: Then $\Jac(C) \cong C$ once a $k$-rational point on $C$ is fixed; $C$ is itself an elliptic curve (abelian variety of dimension $1$).
67	  \item $g \ge 2$: $\Jac(C)$ is a non-trivial $g$-dimensional abelian variety, never isomorphic to $C$ as a scheme.
68	\end{itemize}
69	
70	\section{Implementation route in Lean}
71	
72	Because the full Picard-scheme representability theorem is not available in Mathlib, the formal construction proceeds in two layers:
73	
74	\begin{enumerate}
75	  \item \textbf{Layer I --- direct definition.} Define the Jacobian of $C$ as an object of the category of $k$-schemes over $\Spec k$ carrying the four instances above. In the first instance the underlying scheme can be taken to be the terminal object when the genus is $0$, and for higher genus it is built from an ad-hoc quotient of a suitable symmetric-power-like functor. Since Mathlib lacks general quotients of schemes by finite group actions, we instead rely on the Albanese universal property: the Jacobian is declared as the representing object of the Albanese functor for $C$.
76	
77	  \item \textbf{Layer II --- Abel--Jacobi compatibility.} Chapter~\ref{chap:AbelJacobi} introduces the Abel--Jacobi morphism $C \to \Jac(C)$ and shows that it is universal among morphisms from $C$ to abelian varieties. This is the content of the three protected sorries in AbelJacobi.lean.
78	\end{enumerate}
79	
80	The five protected sorries in Jacobian.lean and the three in AbelJacobi.lean are now in active scope for the prover. They are assigned to the Phase~C parallel track of the project strategy.
81

