The cotangent exact sequence is decomposed into three named ingredients before being assembled into a single theorem.

\begin{definition}[Base-change cotangent map $\alpha$]
  \label{def:cotangent_alpha}
  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqAlpha}
  \uses{def:relative_kaehler_sheaf}
  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{base-change cotangent map} is the natural morphism of quasi-coherent $\struct{X}$-modules
  \[
    \alpha \colon f^*\Omega_{Y/S} \;\longrightarrow\; \Omega_{X/S}
  \]
  whose local description on an affine chart with rings $A = \struct{S}(W)$, $A' = \struct{Y}(f(V))$, $B = \struct{X}(V)$ is the standard map $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A}$ of K\"ahler differentials, $da \otimes b \mapsto b \cdot da$.
\end{definition}

\begin{definition}[Relative-quotient cotangent map $\beta$]
  \label{def:cotangent_beta}
  \lean{AlgebraicGeometry.Scheme.cotangentExactSeqBeta}
  \uses{def:relative_kaehler_sheaf}
  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$ the \emph{relative-quotient cotangent map} is the natural surjection of quasi-coherent $\struct{X}$-modules
  \[
    \beta \colon \Omega_{X/S} \;\longrightarrow\; \Omega_{X/Y}
  \]
  whose local description on an affine chart $A \to A' \to B$ is the surjection $\Omega_{B/A} \to \Omega_{B/A'}$ that kills the $A$-linear derivations factoring through $A'$.
\end{definition}

\begin{lemma}[Exactness of the cotangent short complex]
  \label{lem:cotangent_exact_structure}
  \lean{AlgebraicGeometry.Scheme.cotangentExactSeq_structure}
  \uses{def:cotangent_alpha, def:cotangent_beta}
  The composition $\beta \circ \alpha$ vanishes, the resulting short complex is exact at the middle term, and $\beta$ is an epimorphism. The three ingredients are local statements whose ring-level inputs are the exactness of the Mathlib cotangent sequence $\Omega_{A'/A} \otimes_{A'} B \to \Omega_{B/A} \to \Omega_{B/A'} \to 0$, together with the surjectivity of the right-hand map.
\end{lemma}

\begin{theorem}[Cotangent exact sequence for a composition]
  \label{thm:cotangent_exact_sequence}
  \lean{AlgebraicGeometry.Scheme.cotangent_exact_sequence}
  \uses{def:relative_kaehler_sheaf, def:universal_derivation, def:cotangent_alpha, def:cotangent_beta, lem:cotangent_exact_structure}
  For schemes $X \xrightarrow{f} Y \xrightarrow{g} S$, there is an exact sequence of quasi-coherent $\struct{X}$-modules
  \[
    f^*\Omega_{Y/S} \;\xrightarrow{\;\alpha\;}\; \Omega_{X/S} \;\xrightarrow{\;\beta\;}\;
      \Omega_{X/Y} \;\longrightarrow\; 0,
  \]
  with $\alpha$ and $\beta$ as above. It follows by bundling the three claims of Lemma~\ref{lem:cotangent_exact_structure}.
\end{theorem}

