  \label{def:IsAlbanese}
  \lean{AlgebraicGeometry.IsAlbanese}
  Let $(C, P)$ be a smooth proper geometrically irreducible curve over $k$ with a marked $k$-rational point $P \in C(k)$. A smooth proper geometrically irreducible group scheme $J$ over $k$ is an \emph{Albanese object} for $(C, P)$ if there exists a morphism $\iota \colon C \to J$ sending $P$ to the identity element $\eta \in J$, and such that every morphism $f \colon C \to A$ from $C$ to a smooth proper geometrically irreducible group scheme $A$ with $f(P) = \eta_A$ factors uniquely as $f = \iota \circ g$ for some morphism of group schemes $g \colon J \to A$.
\end{definition}

\begin{theorem}[Uniqueness of the Albanese object]
  \label{thm:IsAlbanese_unique}
  \lean{AlgebraicGeometry.IsAlbanese.unique}
  \uses{def:IsAlbanese}
  Any two Albanese objects for the same pointed curve $(C, P)$ are uniquely isomorphic by an isomorphism compatible with their universal morphisms. The proof is the standard universal-property argument: each of the two universal morphisms factors through the other, the two composites equal the unique self-factorisation $\mathrm{id}$, hence each factorisation is an isomorphism.
\end{theorem}

\subsection{The Jacobian definition}

\begin{definition}[Jacobian]
  \label{def:Jacobian}
  \lean{AlgebraicGeometry.Jacobian}
  \uses{def:genus, def:IsAlbanese}

  The \emph{Jacobian} of $C$ is the abelian variety $\Jac(C)$ over $k$ obtained as the Albanese object of $C$: a smooth proper geometrically irreducible group scheme over $k$ of dimension $g(C)$ equipped with a universal morphism $C \to \Jac(C)$. It is viewed as an object of the category of $k$-schemes over $\Spec k$.

  When $g(C) = 0$ the Jacobian collapses to $\Spec k$ itself, which is the terminal object in the category of $k$-schemes; this case is closed by direct identification with the terminal object. When $g(C) > 0$ the underlying scheme is constructed from the Albanese universal property; the genus-one case recovers $C$ itself (after choosing a $k$-rational point), and the higher genus case yields the non-trivial $g$-dimensional abelian variety.
\end{definition}
